496	<script src="mechsense-core.js"></script>
497	<script>
498	  /* ─── State ─── */
499	  let selMat = 'SW-B';
500	  let selD   = 2.0;
501	  let selNa  = 5;
502	  let massOn = false;
503	  let lastResult = null;
504	
505	  /* ─── Chip setup ─── */
506	  function setupChips(groupId, key, setter) {
507	    document.getElementById(groupId).querySelectorAll('.chip').forEach(c => {
508	      c.addEventListener('click', () => {
509	        document.getElementById(groupId).querySelectorAll('.chip').forEach(x => x.classList.remove('active'));
510	        c.classList.add('active');
511	        setter(parseFloat(c.dataset[key]) || c.dataset[key]);
512	        calculate();
513	      });
514	    });
515	  }
516	
517	  setupChips('mat-chips', 'mat', v => { selMat = v; });
518	  setupChips('d-chips',   'd',   v => { selD   = v; });
519	  setupChips('na-chips',  'na',  v => { selNa  = v; });
520	
521	  ['D', 'rpm', 'mass'].forEach(id => {
522	    const el = document.getElementById(id);
523	    if (el) el.addEventListener('input', calculate);
524	  });
525	
526	  /* ─── Mass toggle ─── */
527	  function toggleMass() {
528	    massOn = !massOn;
529	    document.getElementById('mass-toggle').classList.toggle('on', massOn);
530	    document.getElementById('mass-input').style.display = massOn ? 'block' : 'none';
531	    calculate();
532	  }
533	
534	  /* ─── Calculate ─── */
535	  function calculate() {
536	    const D    = parseFloat(document.getElementById('D').value);
537	    const rpmV = parseFloat(document.getElementById('rpm').value);
538	    const massV = massOn ? parseFloat(document.getElementById('mass').value) : undefined;
539	
540	    const params = {
541	      d: selD,
542	      D: D,
543	      Na: selNa,
544	      mat: selMat,
545	      rpm: (!isNaN(rpmV) && rpmV > 0) ? rpmV : undefined,
546	      mass: (massV !== undefined && !isNaN(massV) && massV > 0) ? massV : undefined,
547	    };
548	
549	    if (!MechSense) return;
550	    const r = MechSense.Resonance.calc(params);
551	    lastResult = r;
552	
553	    if (r.error) {
554	      showError(r.error);
555	      return;
556	    }
557	
558	    renderResult(r);
559	  }
560	
561	  function fmt(v, n) { return MechSense.Utils.fmt(v, n); }
562	
563	  function renderResult(r) {
564	    document.getElementById('result-section').style.display = 'block';
565	
566	    /* status badge */
567	    const badge = document.getElementById('status-badge');
568	    badge.className = 'badge';
569	
570	    if (r.status === 'SAFE') {
571	      badge.classList.add('safe');
572	      badge.querySelector('.badge-label').textContent = '安全';
573	      badge.querySelector('.badge-main').textContent  = '共振なし ✓';
574	      badge.querySelector('.badge-sub').textContent   = `動作比率 ${(r.ratio_surge * 100).toFixed(1)}%（推奨: 70%以下）`;
575	    } else if (r.status === 'WARNING') {
576	      badge.classList.add('warn');
577	      badge.querySelector('.badge-label').textContent = '注意';
578	      badge.querySelector('.badge-main').textContent  = '共振に近い';
579	      badge.querySelector('.badge-sub').textContent   = `動作比率 ${(r.ratio_surge * 100).toFixed(1)}%（推奨: 70%以下）`;
580	    } else if (r.status === 'DANGER') {
581	      badge.classList.add('danger');
582	      badge.querySelector('.badge-label').textContent = '危険';
583	      badge.querySelector('.badge-main').textContent  = 'サージング';
584	      badge.querySelector('.badge-sub').textContent   = `動作比率 ${(r.ratio_surge * 100).toFixed(1)}%（固有振動数超え）`;
585	    } else {
586	      badge.classList.add('info');
587	      badge.querySelector('.badge-label').textContent = '固有振動数';
588	      badge.querySelector('.badge-main').textContent  = `${fmt(r.fn_surge, 1)} Hz`;
589	      badge.querySelector('.badge-sub').textContent   = `${fmt(r.fn_surge_rpm, 0)} min⁻¹`;
590	    }
591	
592	    /* ratio bar */
593	    if (r.ratio_surge !== null) {
594	      document.getElementById('ratio-section').style.display = 'block';
595	      const pct = Math.min(r.ratio_surge * 100, 120);
596	      document.getElementById('ratio-fill').style.width = pct + '%';
597	      document.getElementById('ratio-fill').style.background =
598	        r.status === 'DANGER' ? '#B91C1C' : r.status === 'WARNING' ? '#D97706' : '#15803D';
599	      document.getElementById('ratio-pct').textContent = `${(r.ratio_surge * 100).toFixed(1)}%`;
600	    } else {
601	      document.getElementById('ratio-section').style.display = 'none';
602	    }
603	
604	    /* 4 cards */
